import java.io.ByteArrayInputStream;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

public class SAMLProcessor {
    public static void processSAMLResponse(String samlResponse) throws Exception {
        try {
            // Validate the SAML response XML
            Document document = DocumentBuilderFactory.newInstance().newDocumentBuilder()
                    .parse(new ByteArrayInputStream(samlResponse.getBytes()));
            Element responseElement = (Element) document.getDocumentElement();

            // Extract assertion from the Response element
            Element assertion = (Element) responseElement.getElementsByTagName("Assertion").item(0);

            if (assertion == null) {
                System.out.println("Invalid SAML response: no Assertion found.");
                return;
            }

            // Check that the Response element has correct formatting
            if (!responseElement.getTagName().equals("Response") || !responseElement.getAttribute("xmlns").equals("urn:oasis:names:tc:SAML:2.0:protocol")) {
                System.out.println("Invalid SAML response format.");
                return;
            }

            // Create authenticated session based on assertion content
            String username = getAttribute(assertion, "NameID");
            String sessionToken = createSession(username);
            SessionManager.addSession(sessionToken);

        } catch (Exception e) {
            System.out.println("Error processing SAML response: " + e.getMessage());
        }
    }

    private static String getAttribute(Element assertion, String attributeName) {
        return assertion.getAttribute(attributeName);
    }

    private static String createSession(String username) throws NoSuchAlgorithmException {
        MessageDigest messageDigest = MessageDigest.getInstance("SHA-256");
        byte[] digest = messageDigest.digest(username.getBytes());
        return java.util.Base64.getEncoder().encodeToString(digest);
    }
}